def strip_line_numbers(text):
    lines = text.split('\n')
    result = []
    for line in lines:
        parts = line.split(': ', 1)
        if len(parts) == 2 and parts[0].strip().isdigit():
            result.append(parts[1])
        else:
            result.append(line)
    return '\n'.join(result)

# Read the JSONL
with open('/logs/agent/sessions/projects/-workspace/c02fcbf7-ac78-4580-8a6d-0330187169d6.jsonl', 'r') as f:
    raw = f.read()

# Parse entries
entries = []
for line in raw.split('\n'):
    line = line.strip()
    if line:
        try:
            entries.append(json.loads(line))
        except:
            pass

print(f"Total entries: {len(entries)}")

# Find all sg_read_file results
chunks = {}  # (start_line) -> content

for entry in entries:
    if entry.get('type') == 'tool_result':
        for item in entry.get('content', []):
            if isinstance(item, dict) and item.get('type') == 'text':
                text = item.get('text', '')
                try:
                    parsed = json.loads(text)
                    if isinstance(parsed, dict) and 'content' in parsed:
                        content = parsed['content']
                        url = parsed.get('url', '')
                        if 'udp_proxy_filter_test.cc' in url:
                            # Extract start line from URL
                            m = re.search(r'%3AL(\d+)-(\d+)', url)
                            if m:
